sys_ux_client_script.script:
/**
 * @param {params} params
 * @param {api} params.api
 * @param {any} params.event
 * @param {any} params.imports
 * @param {ApiHelpers} params.helpers
 */
function handler({
    api,
    event,
    helpers,
    imports
}) {
    const PATCH_KEYS = ['value', 'displayValue', 'mandatory', 'readonly', 'messages', 'choices'];

    function applyFieldPatch(field, patch) {
        const updated = Object.assign({}, field);
        PATCH_KEYS.forEach(function(patchKey) {
            if (Object.prototype.hasOwnProperty.call(patch, patchKey)) {
                updated[patchKey] = patch[patchKey];
            }
        });
        if (Object.prototype.hasOwnProperty.call(patch, 'value')) {
            updated.originalValue = patch.value;
        }
        return updated;
    }

    api.setState('isLoading', false);
    const rawOutput = event.payload.data.output?.result;
    const body = rawOutput && typeof rawOutput === 'object' ? rawOutput : {};
    const apiSuccess = body.success === true || body.success === 'true';
    const processResult = {
        success: apiSuccess,
        message: body.message != null ? String(body.message) : '',
        newValues: body.newValues && typeof body.newValues === 'object' && !Array.isArray(body.newValues) ?
            body.newValues : {}
    };

    function failure(msg) {
        api.setState('lastProcessResult', processResult);
        console.error('NextForm process failed:', msg, body);
        api.emit('CTRL_NEXTFORM#PROCESSING_FAILED');
    }

    if (!apiSuccess) {
        return failure(body.message && String(body.message).length ?
            String(body.message) :
            'NextForm processor reported success: false');
    }

    const newValues = processResult.newValues;
    if (!newValues || typeof newValues !== 'object' || Array.isArray(newValues)) {
        return failure('No valid processed values returned');
    }

    // Apply API-reported patches as baselines for fields in newValues (processEditedOnly-safe).
    const fields = api.state.fields;
    const synced = {};
    Object.keys(fields).forEach(function(key) {
        const field = fields[key];
        const fieldName = field?.name;
        if (field && typeof field === 'object' && field.isDataField !== false &&
            fieldName && Object.prototype.hasOwnProperty.call(newValues, fieldName)) {
            synced[key] = applyFieldPatch(field, newValues[fieldName]);
        } else {
            synced[key] = field;
        }
    });
    api.setState('fields', synced);
    api.setState('lastProcessResult', processResult);
    api.setState('isProcessed', true);
    api.emit('CTRL_NEXTFORM#PROCESSING_COMPLETED');
}
